						static function ( $image_url ) use ( $post ) {
							return [
								'link'    => esc_url( $image_url ),
								'updated' => get_the_modified_date( 'c', $post->ID ),
							];
						},
						$images
					)

array_filter(
			$terms,
			static function( $term ) {
				return $term instanceof WP_Term;
			}
		)

array_filter(
