				$wpdb->prepare(
					"SELECT term_id FROM {$wpdb->termmeta}
					 WHERE meta_key = %s AND term_id IN ({$placeholders})",
					$params
				)
			)

array_map(
				static function ( $item ) use ( $column, $value_column, $allowed_classes ) {
					$batch       = new \stdClass();
					$batch->key  = $item->{$column};
					$batch->data = static::maybe_unserialize( $item->{$value_column}, $allowed_classes );

					return $batch;
				},
				$items
			)

array_map(
			static function( $taxonomy ) {
				return [
					'slug' => esc_attr( $taxonomy->name ),
					'name' => esc_html( $taxonomy->label ),
				];
			},
			$taxonomies
		)

array_filter(
					array_map(
						static fn( $title ) => is_string( $title ) ? sanitize_text_field( $title ) : '',
						$titles
					)
				)

array_map(
			static function( $post ): int {
				return is_int( $post ) ? $post : (int) $post->ID;
			},
			$query->posts
		)

